import React, { useState } from "react";

const LabourDashboard = () => {
  const [status, setStatus] = useState("Available");

  const jobs = [
    { id: 1, title: "House Wiring", pay: "₹500/day", location: "Mysore" },
    { id: 2, title: "Fan Installation", pay: "₹300/day", location: "Nearby" }
  ];

  return (
    <div style={styles.page}>

      {/* TOP BAR */}
      <div style={styles.topbar}>
        <h3>Labour Dashboard</h3>

        <button style={styles.logout}>Logout</button>
      </div>

      {/* CONTENT */}
      <div style={styles.container}>

        {/* PROFILE CARD */}
        <div style={styles.card}>
          <h4>My Profile</h4>
          <p>Name: Worker</p>
          <p>Skill: Electrician</p>

          <button
            style={{
              ...styles.statusBtn,
              background: status === "Available" ? "#16a34a" : "#dc2626"
            }}
            onClick={() =>
              setStatus(status === "Available" ? "Busy" : "Available")
            }
          >
            Status: {status}
          </button>
        </div>

        {/* EARNINGS */}
        <div style={styles.card}>
          <h4>Earnings</h4>
          <h2>₹12,500</h2>
          <p style={{ color: "#6b7280" }}>This month</p>
        </div>

        {/* JOBS */}
        <div style={styles.fullCard}>
          <h4>Available Jobs</h4>

          {jobs.map((job) => (
            <div key={job.id} style={styles.jobCard}>
              <h5>{job.title}</h5>
              <p>{job.location}</p>
              <p>{job.pay}</p>

              <button style={styles.accept}>Accept</button>
              <button style={styles.reject}>Reject</button>
            </div>
          ))}

        </div>

      </div>

    </div>
  );
};

export default LabourDashboard;

/* ---------------- STYLES ---------------- */

const styles = {
  page: {
    background: "#f5f6f8",
    minHeight: "100vh",
    fontFamily: "Segoe UI"
  },

  topbar: {
    background: "white",
    padding: "15px 25px",
    display: "flex",
    justifyContent: "space-between",
    borderBottom: "1px solid #e5e7eb"
  },

  logout: {
    padding: "8px 14px",
    border: "1px solid #111",
    borderRadius: "8px",
    background: "white"
  },

  container: {
    display: "grid",
    gridTemplateColumns: "1fr 1fr",
    gap: "20px",
    padding: "20px"
  },

  card: {
    background: "white",
    padding: "15px",
    borderRadius: "12px",
    border: "1px solid #e5e7eb"
  },

  fullCard: {
    gridColumn: "span 2",
    background: "white",
    padding: "15px",
    borderRadius: "12px",
    border: "1px solid #e5e7eb"
  },

  jobCard: {
    padding: "12px",
    border: "1px solid #e5e7eb",
    borderRadius: "10px",
    marginTop: "10px"
  },

  accept: {
    background: "#16a34a",
    color: "white",
    border: "none",
    padding: "6px 12px",
    borderRadius: "6px",
    marginRight: "10px"
  },

  reject: {
    background: "#dc2626",
    color: "white",
    border: "none",
    padding: "6px 12px",
    borderRadius: "6px"
  },

  statusBtn: {
    marginTop: "10px",
    padding: "8px 12px",
    color: "white",
    border: "none",
    borderRadius: "8px"
  }
};
